const config = $input.first().json;
const numVideos = config.num_videos || 1;

// Generate array of video tasks with unique angles
const videoAngles = [
  { angle: "problem-solution", hook_style: "question" },
  { angle: "myth-busting", hook_style: "controversial" },
  { angle: "quick-tip", hook_style: "number" },
  { angle: "before-after", hook_style: "transformation" },
  { angle: "trend-commentary", hook_style: "news" }
];

const tasks = [];
for (let i = 0; i < numVideos; i++) {
  tasks.push({
    json: {
      ...config,
      video_index: i + 1,
      content_angle: videoAngles[i % videoAngles.length].angle,
      hook_style: videoAngles[i % videoAngles.length].hook_style
    }
  });
}

return tasks;

const config = $input.first().json;

// Check if user provided custom inputs
const hasCustomAvatar = config.custom_avatar_description && config.custom_avatar_description.trim() !== '';
const hasCustomScript = config.custom_script && config.custom_script.trim() !== '';

// Build the prompt for Claude
const intentionGuides = {
  "informative": "Focus on educating the viewer. Provide genuine value and actionable insights. Build trust through expertise.",
  "lead_generation": "Create curiosity and desire. Include a soft call-to-action. Make viewers want to learn more about the tool/service.",
  "disruption": "Challenge conventional thinking. Be bold and provocative. Make viewers stop scrolling and pay attention."
};

const hookStyles = {
  "question": "Start with a thought-provoking question that challenges assumptions",
  "controversial": "Start with a bold, slightly controversial statement that makes people want to hear more",
  "number": "Start with a specific number or statistic that grabs attention",
  "transformation": "Start by describing a transformation or before/after scenario",
  "news": "Start with a 'breaking' or trending angle that feels timely"
};

// Build dynamic prompt based on what's needed
let taskInstructions = '';
let responseFormat = '';

if (!hasCustomAvatar && !hasCustomScript) {
  // Generate both
  taskInstructions = `### 1. IMAGE PROMPT (for AI avatar):
Create a detailed prompt for generating a photorealistic human avatar in PORTRAIT orientation. Consider:
- Professional but approachable appearance
- Age 25-40, appropriate for tech content
- Gender: choose what fits the content best
- Head and shoulders framing, looking at camera
- Neutral or vibrant background (NOT white - use colors, gradients, or contextual settings)
- Good lighting, high quality
- Clothing that matches the content theme and target audience
- IMPORTANT: Frame for vertical/portrait composition

### 2. VIDEO SCRIPT (voiceover, 30-45 seconds max):
Create an engaging script that:
- OPENS with a powerful hook using the specified hook style
- Delivers value related to the topic
- Maintains conversational, TikTok-native tone
- Is optimized for text-to-speech (natural phrasing, no special characters)
- Maximum 450 characters
- Ends with engagement driver (question, CTA, or thought-provoker)
- Subtly incorporates the brand if relevant (not salesy)

### 3. CAPTION:
Write a TikTok caption (under 150 chars) + include the trending hashtags.`;
  responseFormat = '{"image_prompt": "detailed image prompt here", "audio_script": "video script here", "caption": "caption with hashtags here", "avatar_gender": "male or female", "content_theme": "2-3 word theme"}';

} else if (hasCustomAvatar && !hasCustomScript) {
  // Only generate script (avatar provided)
  taskInstructions = `### 1. VIDEO SCRIPT (voiceover, 30-45 seconds max):
Create an engaging script that:
- OPENS with a powerful hook using the specified hook style
- Delivers value related to the topic
- Maintains conversational, TikTok-native tone
- Is optimized for text-to-speech (natural phrasing, no special characters)
- Maximum 450 characters
- Ends with engagement driver (question, CTA, or thought-provoker)
- Subtly incorporates the brand if relevant (not salesy)

### 2. CAPTION:
Write a TikTok caption (under 150 chars) + include the trending hashtags.`;
  responseFormat = '{"audio_script": "video script here", "caption": "caption with hashtags here", "content_theme": "2-3 word theme"}';

} else if (!hasCustomAvatar && hasCustomScript) {
  // Only generate avatar (script provided)
  taskInstructions = `### 1. IMAGE PROMPT (for AI avatar):
Create a detailed prompt for generating a photorealistic human avatar in PORTRAIT orientation. Consider:
- Professional but approachable appearance
- Age 25-40, appropriate for tech content
- Gender: choose what fits the content best
- Head and shoulders framing, looking at camera
- Neutral or vibrant background (NOT white - use colors, gradients, or contextual settings)
- Good lighting, high quality
- Clothing that matches the content theme and target audience
- IMPORTANT: Frame for vertical/portrait composition

### 2. CAPTION:
Write a TikTok caption (under 150 chars) + include the trending hashtags.`;
  responseFormat = '{"image_prompt": "detailed image prompt here", "caption": "caption with hashtags here", "avatar_gender": "male or female", "content_theme": "2-3 word theme"}';

} else {
  // Both provided - only generate caption
  taskInstructions = `### 1. CAPTION:
Write a TikTok caption (under 150 chars) + include the trending hashtags.`;
  responseFormat = '{"caption": "caption with hashtags here", "content_theme": "2-3 word theme"}';
}

const prompt = `You are an expert short-form video content strategist specializing in tech and AI content for TikTok and social media.

## CONTENT BRIEF:
- Topic: ${config.topic}
- Brand/Tool: ${config.brand_name}
- Target Audience: ${config.target_audience}
- Content Intention: ${config.intention.toUpperCase()}
- Content Angle: ${config.content_angle}
- Trending Hashtags to incorporate: ${config.trending_hashtags}

## INTENTION GUIDE:
${intentionGuides[config.intention] || intentionGuides.informative}

## HOOK STYLE:
${hookStyles[config.hook_style] || hookStyles.question}

## YOUR TASK:
Create content for a 30-45 second talking-head video in VERTICAL FORMAT (9:16 for TikTok/Reels). Generate:

${taskInstructions}

Respond ONLY with valid JSON in this exact format (no markdown, no code blocks):
${responseFormat}`;

return [{
  json: {
    ...config,
    claude_prompt: prompt,
    has_custom_avatar: hasCustomAvatar,
    has_custom_script: hasCustomScript
  }
}];

const item = $input.first();
const claudeResponse = item.json;
const config = $('🧠 Build Claude Prompt').item.json;

// Extract the text content from Claude's response
let responseText = '';
if (claudeResponse.content && claudeResponse.content[0]) {
  responseText = claudeResponse.content[0].text;
}

// Parse the JSON from Claude's response
let parsed = {};
try {
  let cleanText = responseText.trim();
  // Remove markdown code blocks if present
  if (cleanText.startsWith('```json')) {
    cleanText = cleanText.replace(/```json\n?/, '').replace(/\n?```$/, '');
  } else if (cleanText.startsWith('```')) {
    cleanText = cleanText.replace(/```\n?/, '').replace(/\n?```$/, '');
  }
  parsed = JSON.parse(cleanText.trim());
} catch (e) {
  // Fallback content
  parsed = {
    image_prompt: "",
    audio_script: "",
    caption: "Check out this AI video! #AIvideo #ContentCreation #VideoMarketing",
    avatar_gender: "female",
    content_theme: "AI video"
  };
}

// Build the final image prompt
let finalImagePrompt = '';
if (config.has_custom_avatar && config.custom_avatar_description) {
  // Use custom avatar description and enhance it for image generation
  finalImagePrompt = `Photorealistic portrait photo of ${config.custom_avatar_description}. Head and shoulders framing, looking directly at camera, natural expression, high quality, portrait orientation, vibrant or contextual background (not white), good lighting, 4K quality.`;
} else if (parsed.image_prompt) {
  finalImagePrompt = parsed.image_prompt;
} else {
  finalImagePrompt = "Photorealistic portrait photo of a friendly content creator in their late 20s, casual stylish clothing, head and shoulders framing, looking directly at camera, confident smile, colorful gradient background, good lighting, portrait orientation, high quality";
}

// Build the final script
let finalScript = '';
if (config.has_custom_script && config.custom_script) {
  finalScript = config.custom_script.trim();
} else if (parsed.audio_script) {
  finalScript = parsed.audio_script;
} else {
  finalScript = "What if I told you that creating professional videos no longer requires expensive equipment or editing skills? AI video tools are completely changing the game for content creators. In just minutes, you can go from an idea to a polished video ready for social media. The question is: are you ready to level up your content?";
}

return [{
  json: {
    topic: config.topic,
    intention: config.intention,
    brand_name: config.brand_name,
    video_index: config.video_index,
    script_image: finalImagePrompt,
    script_audio: finalScript,
    caption: parsed.caption || "Check out this AI-generated video! #AIvideo #ContentCreation",
    avatar_gender: parsed.avatar_gender || "female",
    content_theme: parsed.content_theme || "AI video",
    openai_api_key: config.openai_api_key,
    video_resolution: config.video_resolution,
    video_aspect_ratio: config.video_aspect_ratio,
    used_custom_avatar: config.has_custom_avatar,
    used_custom_script: config.has_custom_script
  }
}];

const item = $input.first();
const imageResponse = item.json;
const previousData = $('📋 Parse Claude Response').item.json;

let imageBase64 = '';

// gpt-image-1 returns b64_json by default
if (imageResponse.data && imageResponse.data[0] && imageResponse.data[0].b64_json) {
  imageBase64 = imageResponse.data[0].b64_json;
}

if (!imageBase64) {
  throw new Error('No base64 image data received from OpenAI. Response: ' + JSON.stringify(imageResponse));
}

return [{
  json: {
    ...previousData
  },
  binary: {
    image_data: {
      data: imageBase64,
      mimeType: 'image/png',
      fileName: 'avatar.png'
    }
  }
}];

const uploadResponse = $input.first().json;
const previousData = $('📸 Extract Image Data').item.json;

// Convert tmpfiles URL to direct download URL
const publicImageUrl = uploadResponse.data.url.replace(
  /^http:\/\/tmpfiles\.org\/(\d+)\/(.*)$/i,
  'https://tmpfiles.org/dl/$1/$2'
);

return [{
  json: {
    ...previousData,
    public_image_url: publicImageUrl
  }
}];

return items.map(item => {
  const b = item.binary?.audio;
  if (!b) return item;

  item.binary.audio_mp3 = {
    ...b,
    fileName: 'voiceover.mp3',
    mimeType: 'audio/mpeg'
  };

  return item;
});

const audioUpload = $input.first().json;
const previousData = $('💾 Store Image URL').item.json;

// Convert tmpfiles URL to direct download URL
const publicAudioUrl = audioUpload.data.url.replace(
  /^http:\/\/tmpfiles\.org\/(\d+)\/(.*)$/i,
  'https://tmpfiles.org/dl/$1/$2'
);

return [{
  json: {
    image_url: previousData.public_image_url,
    audio_url: publicAudioUrl,
    resolution: previousData.video_resolution || '720p',
    aspect_ratio: previousData.video_aspect_ratio || '9:16',
    topic: previousData.topic,
    intention: previousData.intention,
    brand_name: previousData.brand_name,
    video_index: previousData.video_index,
    script_audio: previousData.script_audio,
    script_image: previousData.script_image,
    caption: previousData.caption,
    content_theme: previousData.content_theme
  }
}];

const veedResult = $input.first().json;
const prepData = $('📦 Prepare VEED Request').item.json;

const now = new Date();
const monthNames = ['January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December'];
const monthFolder = `${monthNames[now.getMonth()]} ${now.getFullYear()}`;
const dateStr = now.toISOString().split('T')[0];
const fileName = `${dateStr}-${prepData.topic.replace(/\s+/g, '_')}_${prepData.video_index}_${Date.now()}.mp4`;

// Get video URL from VEED response - check various possible response structures
let videoUrl = '';
if (veedResult.video && veedResult.video.url) {
  videoUrl = veedResult.video.url;
} else if (veedResult.output && veedResult.output.video_url) {
  videoUrl = veedResult.output.video_url;
} else if (veedResult.videoUrl) {
  videoUrl = veedResult.videoUrl;
} else if (veedResult.url) {
  videoUrl = veedResult.url;
}

return [{
  json: {
    video_url: videoUrl,
    file_name: fileName,
    month_folder: monthFolder,
    topic: prepData.topic,
    intention: prepData.intention,
    brand_name: prepData.brand_name,
    video_index: prepData.video_index,
    script_audio: prepData.script_audio,
    script_image: prepData.script_image,
    caption: prepData.caption,
    content_theme: prepData.content_theme,
    image_url: prepData.image_url,
    audio_url: prepData.audio_url,
    status: videoUrl ? 'done' : 'error',
    veed_raw_response: veedResult
  }
}];

const driveResult = $input.first().json;
const prepData = $('📁 Prepare Upload').item.json;

const driveFileUrl = driveResult.webViewLink || 
  `https://drive.google.com/file/d/${driveResult.id}/view`;

return [{
  json: {
    topic: prepData.topic,
    intention: prepData.intention,
    brand_name: prepData.brand_name,
    content_theme: prepData.content_theme,
    script_audio: prepData.script_audio,
    script_image: prepData.script_image,
    caption: prepData.caption,
    image_url: prepData.image_url,
    audio_url: prepData.audio_url,
    video_url: driveFileUrl,
    status: 'done',
    created_at: new Date().toISOString()
  }
}];
